SourceCode.Declaration:
/// <summary>
/// Contract class for the Unsold Journal Import Log process in the ETGSPAIN model.
/// This class manages the parameters required for the import operation, including the journal ID, location, and file input.
/// Implements the SysOperationValidatable interface for parameter validation.
/// </summary>
[DataContract,
SysOperationContractProcessing(classStr(ETGSPAINUnsoldJournalImportLogUIBuilder))]
class ETGSPAINUnsoldJournalImportLogContract implements SysOperationValidatable
{
    ETGSPAINUnsoldJournalId etgspainUnsoldJournalId;
    InventLocationId        inventLocationId;
    System.IO.Stream        inputDataStream;

}

Method.Source:
/// <summary>
/// Parameter for the Unsold Journal ID.
/// </summary>
/// <param name="_etgspainUnsoldJournalId">Journal ID to be set.</param>
/// <returns>Returns the Unsold Journal ID.</returns>
[DataMember]
public ETGSPAINUnsoldJournalId parmETGSPAINUnsoldJournalId(ETGSPAINUnsoldJournalId _etgspainUnsoldJournalId = etgspainUnsoldJournalId)
{
    etgspainUnsoldJournalId = _etgspainUnsoldJournalId;
    return etgspainUnsoldJournalId;
}

/// <summary>
/// Parameter for the output location (warehouse).
/// </summary>
/// <param name="_inventLocationId">The location ID to be set.</param>
/// <returns>Returns the output location ID.</returns>
[DataMember]
public InventLocationId parmInventLocationId(InventLocationId _inventLocationId = inventLocationId)
{
    inventLocationId = _inventLocationId;
    return inventLocationId;
}

/// <summary>
/// Parameter for the file stream to be uploaded.
/// </summary>
/// <param name="_value">The input data stream to be set.</param>
public System.IO.Stream parmInputDataStream(System.IO.Stream _value = inputDataStream)
{
    inputDataStream = _value;
    return inputDataStream;
}

/// <summary>
/// Validates if the contract parameters are correctly set.
/// </summary>
/// <returns>
/// Returns true if all parameters are valid, otherwise false.
/// </returns>
public boolean validate()
{
    boolean isValid = true;

    if (!etgspainUnsoldJournalId)
    {
        isValid = checkFailed(strFmt("@ETGSPAINLabels:NoSelected", "@ETGSPAINLabels:InventJournalNum"));
    }

    if (!inventLocationId)
    {
        isValid = checkFailed(strFmt("@ETGSPAINLabels:NoSelected", "@ETGSPAINLabels:InventLocationOutput"));
    }

    if (!inputDataStream)
    {
        isValid = checkFailed(strFmt("@ETGSPAINLabels:NoSelected", "@ETGSPAINLabels:UploadFileData"));
    }

    return isValid;
}
